import React, { useCallback, useMemo, useState } from 'react';
import { Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd } from '../../../utils/formatters';
import { MONTH_OPTIONS, YEAR_OPTIONS } from '../../../utils/exportExcel';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { B01Row } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-b01-dn';
const PAGE_ID = 'baocao-b01-dn';

const B01DnPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const now = new Date();
  const [month, setMonth] = useState(now.getMonth() + 1);
  const [year, setYear] = useState(now.getFullYear());
  const [rows, setRows] = useState<B01Row[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getB01Dn({ month, year })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [month, year, dispatch]);

  const filterItems = useMemo(
    () => [
      {
        testId: `${TEST_ID}-field-month`,
        content: (
          <div className={erp.field}>
            <Select
              label="Tháng"
              value={String(month)}
              onChange={e => setMonth(Number(e.target.value))}
              options={MONTH_OPTIONS}
              size="small"
            />
          </div>
        ),
      },
      {
        testId: `${TEST_ID}-field-year`,
        content: (
          <div className={erp.field}>
            <Select
              label="Năm"
              value={String(year)}
              onChange={e => setYear(Number(e.target.value))}
              options={YEAR_OPTIONS}
              size="small"
            />
          </div>
        ),
      },
    ],
    [month, year],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="B01-DN"
      loading={loading}
      hasData={rows.length > 0}
      filterItems={filterItems}
      onLoad={handleLoad}
      exportPath="/reports/financial/b01-dn/export-excel"
      exportParams={{ month, year }}
      exportFilename={`B01-T${month}-${year}.xlsx`}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Chỉ tiêu</th>
            <th className={reportStyles.colRight}>Nợ ĐK</th>
            <th className={reportStyles.colRight}>Có ĐK</th>
            <th className={reportStyles.colRight}>Nợ CK</th>
            <th className={reportStyles.colRight}>Có CK</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i} className={r.isTotal ? reportStyles.rowTotal : undefined}>
              <td>
                {r.code} — {r.name}
              </td>
              <td className={reportStyles.colRight}>{formatVnd(r.openingDebit)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.openingCredit)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.closingDebit)}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.closingCredit)}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default B01DnPage;
